Future<CpuRenderFrame> renderCpuFrame({
  required String moduleId,
  required Vector2 viewPan,
  required double viewZoom,
  required int iterations,
  required double bailout,
  required Vector2 juliaC,
  required int width,
  required int height,
  int sampleCount = 4,
}) async {
  // Mandelbrot viewport baseline: y in [-1.5, 1.5] => half-range 1.5
  // (matches tile/isolate renderer mapping).
  final viewport = CpuViewportMapping(
    viewPan: viewPan,
    viewZoom: viewZoom,
    width: width,
    height: height,
  );
  final bytes = Uint8List(width * height * 4);
  final samplesPerAxis = math.max(1, math.sqrt(sampleCount).round());
  final totalSamples = samplesPerAxis * samplesPerAxis;

  final formula = cpuFormulaForModuleId(moduleId);

  for (int y = 0; y < height; y++) {
    for (int x = 0; x < width; x++) {
      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < samplesPerAxis; sy++) {
        for (int sx = 0; sx < samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: width,
            sample: sx,
            samplesPerAxis: samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: height,
            sample: sy,
            samplesPerAxis: samplesPerAxis,
          );
          final c = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(c.$1, c.$2, iterations, bailout, juliaC);
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (y * width + x) * 4;
      bytes[idx + 0] = (rAcc / totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return CpuRenderFrame(rgba: bytes, width: width, height: height);
}

