}) {
  final bytes = Uint8List(w * h * 4);
  final samplesPerAxis = math.max(1, math.sqrt(sampleCount).round());
  final totalSamples = samplesPerAxis * samplesPerAxis;

  final juliaC = Vector2(juliaCX, juliaCY);
